10	      expect(quote({
11	        customer: { yearsWithMHPCO: 0 },
12	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }]
13	      })).toEqual({ premium: 105 });
14	    });
15	    it("single amulet yields 65 G (60 base + 5 fee)", () => {
16	      expect(quote({
17	        customer: { yearsWithMHPCO: 0 },
18	        items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }]
19	      })).toEqual({ premium: 65 });
20	    });
21	    it("single staff yields 85 G (80 base + 5 fee)", () => {
22	      expect(quote({
23	        customer: { yearsWithMHPCO: 0 },
24	        items: [{ type: "staff", material: "oak", enchantment: 0, cursed: false }]
25	      })).toEqual({ premium: 85 });
